/** Ids of every monster that has finished line-art. */
export function monsterArtIds(): string[] {
  return Object.keys(MONSTER_ART);
}

/**
 * Standalone SVG markup for a monster's line-art — a self-contained `<svg>`
 * string (strokes in `stroke`, no fill) that scales to fill its box. Used where
 * an inline SVG is needed outside React's tree, e.g. the landing hover-draw.
 */
export function monsterArtSvg(id: string, stroke = 'currentColor'): string {
  const art = MONSTER_ART[id];
  if (!art) return '';
  const paths = art.paths.map((d) => `<path d="${d}"/>`).join('');
  // No width/height — the consumer's CSS sets the height and width follows the
  // viewBox aspect ratio, so every monster renders at the same height.
  return (
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${art.viewBox}"` +
    ` preserveAspectRatio="xMidYMid meet"` +
    ` fill="none" stroke="${stroke}">${paths}</svg>`
  );
}
